/**
 * 그리드의 내용을 엑셀로 다운로드 한다.
 * @return
 */
scwin.btnDownExcel_onclick = function() {
	var menuNm = $p.getComponentById("wfm_title").scope.$p.getComponentById("tbxScreenTitle").getValue();
	var subTitle1 = spnTitleYear.getValue();
	var subTitle2 = spnSubTitle.getValue();
	var subTitleNm = subTitle1 + subTitle2;
	/*
	// <br> 제거_231023
	var grdData = dltRe100List.getAllJSON();
	for(var i = 0; i < grdData.length; i++) {
		var currentIemCd = grdData[i].iemCd;
		if(currentIemCd.includes("<br/>")) {
			// <br>제거 + (MWh)옆의 공백 없애기
			currentIemCd = currentIemCd.replace("<br/>", "").replace(/\s+\(MWh\)/, "(MWh)");
			grdData[i].iemCd = currentIemCd;
		}
	}
	dltRe100List.setJSON(grdData, false);
	*/

	// 다운로드 후 셀 색상 설정을 위한 dltRe100List.setJSON_231024
	var dltData = dltRe100List.getAllJSON();
	var strtDate = dmaSearchParam.get("strtDt");
	for (data of scwin.dataSet) {
		tempData = dltData[data.row];
		tempData.re100Year = strtDate;
		tempData.iemNm = data.iemNm;
		tempData.ecsElcpwstnDivCd = data.ecsElcpwstnDivCd;
		dltData[data.row] = tempData;
	}
	dltRe100List.setJSON(dltData);

	// 엑셀 내부 타이틀 추가_240105
	var infoArr = [];
	var infoObj = {
		rowIndex 	: 0,
		colIndex 	: 0,
		rowSpan 	: 0,
		colSpan 	: 16,
		text 		: `${menuNm}_` + `${subTitleNm}`,
		textAlign 	: "left"
	};
	infoArr.push(infoObj);

	comLib.downloadExcel(grdRe100List, {
		fileName : `${menuNm}_` + `${subTitleNm}.xlsx`,
		type : 1,
		autoSizeColumn : true,
		useDataFormat: true,
		applyDataFormat : true,
		startRowIndex : 1,
		startColumnIndex : 0,
		colMerge : true,
		colMergeValue : true,
		mergeCell : true
	}, infoArr);

	// 다운로드 후 셀 색상 설정
	scwin.setGridReadOnly();
};

/**
 * 엑셀의 내용을 그리드에 업로드 한다.
 * @return
 */
scwin.btnUploadExcel_onclick = function() {
	var endColumnIndex = grdRe100List.getColumnCount();
	var options = {
		type : 1,
		headerExist : 1,
		startRowIndex : 1,
		startColumnIndex : 0,
		endColumnIndex : endColumnIndex,
		status: "C",
		useMaxByteLength : true
	};
	comLib.uploadExcel(grdRe100List, options);
};

/**
 * 엑셀 내용을 그리드에 저장한다.
 * @return
 */
scwin.grdRe100List_onfilereadend = function(value) {
	var dltData = dltRe100List.getAllJSON();
	var grdData = grdRe100List.getAllJSON();
	var strtDate = dmaSearchParam.get("strtDt");

	for (data of scwin.dataSet) {
		tempData = dltData[data.row];
		tempData.re100Year = strtDate;
		tempData.iemNm = data.iemNm;
		tempData.ecsElcpwstnDivCd = data.ecsElcpwstnDivCd;
		dltData[data.row] = tempData;
	}
	dltRe100List.setJSON(dltData);

	scwin.setGridReadOnly();
	scwin.excelUp = true;
};
